-- 환자 기본 정보
CREATE TABLE patients (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  gender TEXT,
  department TEXT NOT NULL,
  status TEXT DEFAULT 'active',
  created_at TIMESTAMPTZ DEFAULT now()
);
-- 예약 정보
CREATE TABLE bookings (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  patient_id UUID REFERENCES patients(id) ON DELETE CASCADE,
  doctor TEXT,
  appt_date DATE NOT NULL,
  appt_time TEXT,
  symptoms TEXT,
  status TEXT DEFAULT 'scheduled',
  created_at TIMESTAMPTZ DEFAULT now()
);
-- 민감 정보 (암호화 저장)
CREATE TABLE patient_sensitive (
  id SERIAL PRIMARY KEY,
  patient_id UUID REFERENCES patients(id) ON DELETE CASCADE,
  birth_enc TEXT,
  phone_enc TEXT
);
-- RLS 활성화
ALTER TABLE patients ENABLE ROW LEVEL SECURITY;
ALTER TABLE bookings ENABLE ROW LEVEL SECURITY;
ALTER TABLE patient_sensitive ENABLE ROW LEVEL SECURITY;
CREATE POLICY auth_only ON patients FOR ALL USING (auth.role()='authenticated');
CREATE POLICY auth_only ON bookings FOR ALL USING (auth.role()='authenticated');
CREATE POLICY auth_only ON patient_sensitive FOR ALL USING (auth.role()='authenticated');

// Google 로그인 구현
async function loginWithGoogle() {
  const { error } = await db.auth.signInWithOAuth({
    provider: 'google',
    options: {
      redirectTo: 'https://내도메인.com/callback'
    }
  });
}

// 세션 확인
db.auth.onAuthStateChange((event, session) => {
  if (session) showApp(session.user.email);
  else showLogin();
});

// functions/api/notify.js
export async function onRequest(context) {
  const url = new URL(context.request.url);
  const msg  = url.searchParams.get('msg') || '새 예약';
  const name = url.searchParams.get('name') || '';
  const dept = url.searchParams.get('dept') || '';
  const token  = context.env.TELEGRAM_TOKEN;
  const chatId = context.env.TELEGRAM_CHAT_ID;
  const text = '새 예약 알림\n환자: ' + name + '\n진료과: ' + dept;
  const apiUrl = 'https://api.telegram.org/bot' + token + '/sendMessage';
  const res = await fetch(apiUrl, {
    method: 'POST',
    headers: {'Content-Type':'application/json'},
    body: JSON.stringify({chat_id: chatId, text: text})
  });
  return new Response(JSON.stringify(await res.json()));
}

// 예약 실시간 구독
const channel = db.channel('bookings');
channel.on('postgres_changes', {
  event: '*',
  schema: 'public',
  table: 'bookings'
}, (payload) => {
  if (payload.eventType === 'INSERT')
    addRow(payload.new);
}).subscribe();

// Cloud Functions 프록시 예시 (보안 API 호출)
exports.predict = async (req, res) => {
  const { GoogleAuth } = require("google-auth-library");
  const auth = new GoogleAuth();
  const client = await auth.getClient();

  const endpoint = "YOUR_VERTEX_AI_ENDPOINT";
  const instance = req.body; // {bmi, blood_pressure, ...}

  const response = await client.request({
    url: endpoint,
    method: "POST",
    data: { instances: [instance] }
  });

  res.json(response.data.predictions[0]);
};
